634	        function puschTx(obj, currTimingInfo)
635	            % Transmit the PUSCH scheduled for current time
636	
637	            if ~isempty(obj.PUSCHInfo)
638	                % Fill PUSCH packet details
639	                packet = obj.PacketStruct;
640	                puschInfo = obj.PUSCHInfo;
641	                txPowerControl(obj, obj.PUSCHPowerControlType);
642	                if isempty(obj.MacPDU)
643	                    obj.PacketTransmissionStarted.TransmissionType = "ReTx";
644	                    macPDU = obj.HARQBuffers{puschInfo.HARQID+1};
645	                    packet.Data = puschData(obj, puschInfo, []);
646	                else
647	                    obj.PacketTransmissionStarted.TransmissionType = "NewTx";
648	                    macPDU = obj.MacPDU.Packet;
649	                    obj.HARQBuffers{puschInfo.HARQID+1} = macPDU;
650	                    % Get the PUSCH data after PHY processing
651	                    packet.Data = puschData(obj, puschInfo, obj.MacPDU.Packet);
652	                    % Store the associated packet tags to deal with possible retransmission
653	                    obj.ReTxTagBuffer{puschInfo.HARQID+1} = obj.MacPDU.Tags;
654	                end
655	                % Apply FFT Scaling to the transmit power
656	                powerScalingFactor = sqrt((obj.WaveformInfo.Nfft^2) / (12*numel(obj.PUSCHInfo.PUSCHConfig.PRBSet)));
657	                packet.Power = mag2db(db2mag(obj.AdjustedTransmitPower-30)*powerScalingFactor) + 30; %dBm
658	                packet.StartTime = currTimingInfo.Time/1e9;
659	                % MIMO precoding, TS 38.211 Section 6.3.1.5
660	                if (strcmpi(puschInfo.PUSCHConfig.TransmissionScheme,'codebook'))
661	                    wtx = nrPUSCHCodebook(puschInfo.PUSCHConfig.NumLayers,puschInfo.PUSCHConfig.NumAntennaPorts, ...
662	                        puschInfo.PUSCHConfig.TPMI,puschInfo.PUSCHConfig.TransformPrecoding);
663	                else % 'nonCodebook'
664	                    wtx = eye(puschInfo.PUSCHConfig.NumLayers);
665	                end
666	                packet.Metadata.PrecodingMatrix = wtx;
667	                packet.Metadata.PacketConfig = puschInfo.PUSCHConfig; % PUSCH Configuration
668	                packet.Metadata.TargetCodeRate = puschInfo.TargetCodeRate;
669	                packet.Metadata.RNTI = puschInfo.PUSCHConfig.RNTI;
670	                packet.Metadata.PacketType = obj.PXSCHPacketType;
671	                startSym = puschInfo.PUSCHConfig.SymbolAllocation(1);
672	                endSym = puschInfo.PUSCHConfig.SymbolAllocation(1)+puschInfo.PUSCHConfig.SymbolAllocation(2)-1;
673	                [startSampleIdx, endSampleIdx] = sampleIndices(obj, puschInfo.NSlot, ...
674	                    startSym, endSym);
675	                packet.Duration = round(sum(obj.CarrierInformation.SymbolDurations(startSym+1:endSym+1))/1e9,9);
676	                packet.Metadata.NumSamples = endSampleIdx-startSampleIdx+1;
677	                packet.SampleRate = obj.WaveformInfo.SampleRate;
678	                packet.Tags = obj.ReTxTagBuffer{puschInfo.HARQID+1};
679	
680	                % Update stats
681	                obj.StatTransmittedPackets = obj.StatTransmittedPackets + 1;
682	
683	                %Send the packet
684	                obj.SendPacketFcn(packet);
685	
686	                % Update event data
687	                obj.PacketTransmissionStarted.HARQID = puschInfo.HARQID;
688	                obj.PacketTransmissionStarted.SignalType = "PUSCH";
689	                obj.PacketTransmissionStarted.PDU = macPDU;

