    obj.PacketReceptionEnded.TimingInfo(3) = max(obj.PacketReceptionEnded.TimingInfo(3), rxTimingInfo(3));
    obj.PacketReceptionEnded.SignalType = obj.PacketReceptionEnded.SignalType+"+CSIRS";
