  net = wirelessNetworkSimulator.init();
  addNodes(net, gnb);
  addNodes(net, ue);
  channelConfig = struct(DelayProfile="CDL-B", DelaySpread=100e-9, MaximumDopplerShift=5);
  channels = hNRCreateCDLChannels(channelConfig, gnb, ue);
  customChan = hNRCustomChannelModel(channels);
  addChannelModel(net, @customChan.applyChannelModel);
  run(net, 5e-3);
  disp('PASSED');
catch ME
  fprintf('FAILED: %s\n', ME.message);
  for k = 1:numel(ME.stack)
    fprintf('  at %s line %d\n', ME.stack(k).name, ME.stack(k).line);
  end
end
