            if isempty(connConfig.CSIReportPeriodicity)
                % Automatic report periodicity and offset calculation in slots
                connConfig.CSIReportPeriod = [csirsTxPeriod(1) mod(reportPeriodOffset, csirsTxPeriod(1))];
            else
