            configIdx = find(panelConfigs(:,1) == csirs1.NumCSIRSPorts);
            if ~isempty(configIdx)
                csiReportConfig.PanelDimensions = panelConfigs(configIdx(1), 2:3); % Read the first index matched
            end
        end

