        signalTypeVal = data.SignalType;
    else
        signalTypeVal = currSignalType + "+" + data.SignalType;
    end
    obj.SchedulingLog{linkIndex}{rowIdx, sigTypeCol}(rntiIdx) = signalTypeVal;
end

